.darma-loader-darma-custom-633 {color: var(--loader-color, #be123c);
   height: 30px;
   aspect-ratio: 2;
   background: radial-gradient(farthest-side,var(--loader-color, #be123c) 90%,#0000) 0 0/8px 8px, radial-gradient(farthest-side,var(--loader-color, #be123c) 90%,#0000) 0 0/8px 8px, radial-gradient(farthest-side,var(--loader-color, #be123c) 90%,#0000) 0 0/8px 8px, radial-gradient(farthest-side,var(--loader-color, #be123c) 90%,#0000) 0 0/8px 8px, radial-gradient(farthest-side,currentColor 90%,#0000) 0 0/8px 8px, linear-gradient(currentColor 0 0) center/100% 10px , linear-gradient(currentColor 0 0) right/50% 100%;
   background-repeat:no-repeat;
   animation: darma-loader-darma-custom-633-l10 2s infinite;
}
@keyframes darma-loader-darma-custom-633-l10  {
  0% {background-position:top 1px right 1px,right 1px bottom 1px,top 1px left 31px,bottom 1px left 31px, -10px 50%,50%,right}
50%, 60%{background-position:top 1px right 1px,right 1px bottom 1px,top 1px left 31px,bottom 1px left 31px,left 75% top 50%,50%,right}
80% {background-position:75% 50%,75% 50%,75% 50%,75% 50%,left 75% top 50%,50%,right}
80.01% {background-position:75% 50%,75% 50%,75% 50%,75% 50%,-10px 50%,50%,right}
100%{background-position:top 1px right 1px,right 1px bottom 1px,top 1px left 31px,bottom 1px left 31px,-10px 50%,50%,right}
}

